        {
            num = num + i + 1;
            Print("OnInit,id:" + Text(i) + ",num:" + Text(num));
        }
    }

    OnReady()
    {
        Integer i;
        Range[i = 0:DataCount - 1]
        {
            num = num + i + 1;
            Print("OnReady,id:" + Text(i) + ",num:" + Text(num));
        }
    }

    OnBar(ArrayRef<Integer> indexs)
    {
        if(CurrentBar == 1){
            Integer i;
            Range[i = 0:DataCount - 1]
